import React, { useState } from "react";
import axios from "axios";
import "./ChatBox.css";

function ChatBox() {

  const [query, setQuery] = useState("");

  const [persons, setPersons] = useState(1);

  const [response, setResponse] = useState({
    ai_response: "",
    budget: {},
    recommendations: [],
    safety: {},
    itinerary: []
  });

  // ------------------------------------
  // Send Query
  // ------------------------------------

  const sendQuery = async () => {

    try {

      const res = apost(
        "http://127.0.0.1:8000/chat",
        {
          query,
          persons
        }
      );

      setResponse(res.data);

    } catch (error) {

      console.log(error);

      alert("Backend connection failed");
    }
  };

  // ------------------------------------

  return (

    <div className="container">

      <h1>
        🇮🇳 India AI Travel Planner
      </h1>

      <p>
        Plan your budget-friendly India trip with AI recommendations,
        nearby places, safety analysis and smart itinerary planning.
      </p>

      {/* Query Box */}

      <textarea
        placeholder="Example: Plan 3 days Goa trip under 50k"
        value={query}
        onChange={(e) =>
          setQuery(e.target.value)
        }
      />

      {/* Persons */}

      <input
        type="number"
        min="1"
        value={persons}
        onChange={(e) =>
          setPersons(e.target.value)
        }
      />

      {/* Button */}

      <button onClick={sendQuery}>
        Plan Trip
      </button>

      {/* Response */}

      <div className="response">

        {/* AI Response */}

        <h2>🤖 AI Response</h2>

        <p>{response.ai_response}</p>

        {/* Budget */}

        <h2>💰 Budget Details</h2>

        <p>
          🏨 Hotel Cost:
          ₹{response?.budget?.hotel || 0}
        </p>

        <p>
          🍛 Food Cost:
          ₹{response?.budget?.food || 0}
        </p>

        <p>
          🚌 Transport Cost:
          ₹{response?.budget?.transport || 0}
        </p>

        <p>
          📦 Misc Cost:
          ₹{response?.budget?.misc || 0}
        </p>

        <h3>
          Total Budget:
          ₹{response?.budget?.total || 0}
        </h3>

        {/* Recommendations */}

        <h2>
          📍 Nearby Recommended Places
        </h2>

        {
          response.recommendations &&
          response.recommendations.length > 0 ? (

            response.recommendations.map(
              (place, index) => (

                <div
                  className="card"
                  key={index}
                >

                  <h3>
                    {place.name}
                  </h3>

                  <p>
                    <b>🏨 Hotel:</b>
                    {" "}
                    {place.hotel_name}
                  </p>

                  <p>
                    <b>🏙 City:</b>
                    {" "}
                    {place.city}
                  </p>

                  <p>
                    <b>🗺 State:</b>
                    {" "}
                    {place.state}
                  </p>

                  <p>
                    <b>🎯 Type:</b>
                    {" "}
                    {place.type}
                  </p>

                  <p>
                    <b>💸 Estimated Budget:</b>
                    ₹{place.budget}
                  </p>

                  <p>
                    <b>👩 Women Safety:</b>
                    {" "}
                    {place.women_safety}
                  </p>

                  <p>
                    <b>🛡 Safety Score:</b>
                    {" "}
                    {place.safety_score}
                  </p>

                  <p>
                    <b>👥 Crowd Level:</b>
                    {" "}
                    {place.crowd_level}
                  </p>

                  <p>
                    <b>⏰ Best Time:</b>
                    {" "}
                    {place.best_time}
                  </p>

                  {/* Good Places */}

                  <h4>
                    ✅ Good Places Nearby
                  </h4>

                  <ul>

                    {
                      place.good_places &&
                      place.good_places.length > 0 ? (

                        place.good_places.map(
                          (good, i) => (
                            <li key={i}>
                              {good}
                            </li>
                          )
                        )

                      ) : (

                        <li>
                          No nearby good places available
                        </li>
                      )
                    }

                  </ul>

                  {/* Bad Places */}

                  <h4>
                    ⚠ Avoid These Areas
                  </h4>

                  <ul>

                    {
                      place.bad_places &&
                      place.bad_places.length > 0 ? (

                        place.bad_places.map(
                          (bad, i) => (
                            <li key={i}>
                              {bad}
                            </li>
                          )
                        )

                      ) : (

                        <li>
                          No risky areas reported
                        </li>
                      )
                    }

                  </ul>

                  {/* Distances */}

                  <p>
                    🚆 Railway Station:
                    {" "}
                    {place.railway_distance} km
                  </p>

                  <p>
                    🚌 Bus Stand:
                    {" "}
                    {place.bus_distance} km
                  </p>

                  <p>
                    ✈ Airport:
                    {" "}
                    {place.airport_distance} km
                  </p>

                </div>
              )
            )

          ) : (

            <p>
              No places found
            </p>
          )
        }

        {/* Safety */}

        <h2>
          🛡 Safety Information
        </h2>

        <p>
          Women Safety:
          {" "}
          {response?.safety?.women_safety}
        </p>

        <p>
          Child Friendly:
          {" "}
          {response?.safety?.child_friendly}
        </p>

        <p>
          Night Travel Risk:
          {" "}
          {response?.safety?.night_risk}
        </p>

        {/* Itinerary */}

        <h2>
          🗓 Trip Itinerary
        </h2>

        {
          response.itinerary &&
          response.itinerary.length > 0 ? (

            response.itinerary.map(
              (day, index) => (
                <p key={index}>
                  {day}
                </p>
              )
            )

          ) : (

            <p>
              No itinerary available
            </p>
          )
        }

      </div>

    </div>
  );
}

export default ChatBox;
